const libro = {
  titulo: 'El Aleph',
  autor: 'Borges',
  paginas: 196
};

const { titulo, autor, paginas } = libro;

console.log(titulo);  // 'El Aleph'
console.log(autor);   // 'Borges'
console.log(paginas); // 196

const config = {
  host: 'localhost',
  puerto: 3000
};

// Renombramos 'puerto' a 'numeroPuerto'
const { host, puerto: numeroPuerto } = config;

console.log(host);        // 'localhost'
console.log(numeroPuerto); // 3000
// console.log(puerto);   // ❌ Error: puerto no existe como variable

const usuario = { nombre: 'Pedro', email: 'pedro@mail.com' };

// 'rol' no existe en el objeto, usamos 'visitante' como defecto
const { nombre, email, rol = 'visitante' } = usuario;

console.log(nombre); // 'Pedro'
console.log(email);  // 'pedro@mail.com'
console.log(rol);    // 'visitante'
